// Stage 1: Apify discovery — hashtag posts → profile scraping → raw_prospects
// Ejecutado como Code node (typeVersion 2) en n8n. Tiene acceso a process.env y fetch.

const APIFY_TOKEN = process.env.APIFY_TOKEN;
const SUPABASE_URL = process.env.SUPABASE_URL;
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_KEY;

const sleep = ms => new Promise(r => setTimeout(r, ms));

async function apifyRunAndWait(actorSlug, input, maxWaitMs = 240000) {
  const start = await fetch(
    `https://api.apify.com/v2/acts/${actorSlug}/runs?token=${APIFY_TOKEN}`,
    { method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(input) }
  );
  const startData = await start.json();
  if (!startData?.data?.id) throw new Error('Apify start failed: ' + JSON.stringify(startData));

  const runId = startData.data.id;
  const datasetId = startData.data.defaultDatasetId;
  const deadline = Date.now() + maxWaitMs;

  while (Date.now() < deadline) {
    await sleep(6000);
    const info = await (await fetch(`https://api.apify.com/v2/actor-runs/${runId}?token=${APIFY_TOKEN}`)).json();
    const status = info.data?.status;
    if (status === 'SUCCEEDED') break;
    if (status === 'FAILED' || status === 'ABORTED') throw new Error(`Apify run ${status} — runId: ${runId}`);
  }

  const items = await (await fetch(`https://api.apify.com/v2/datasets/${datasetId}/items?token=${APIFY_TOKEN}&limit=200`)).json();
  return Array.isArray(items) ? items : [];
}

async function supabaseUpsert(table, rows) {
  if (!rows.length) return [];
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${table}?on_conflict=source,source_id`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${SUPABASE_KEY}`,
      'apikey': SUPABASE_KEY,
      'Prefer': 'return=representation,resolution=ignore-duplicates',
    },
    body: JSON.stringify(rows),
  });
  if (!res.ok) throw new Error(`Supabase upsert ${table}: ${await res.text()}`);
  return res.json();
}

// ── Hashtags para nicho ia-negocios ──────────────────────────────────────────
const HASHTAGS = [
  'ianegocios', 'cursosdeia', 'iaparaemprendedores',
  'promptengineering', 'chatgptnegocios', 'automatizacionia',
  'inteligenciaartificialnegocios',
];
const directUrls = HASHTAGS.map(h => `https://www.instagram.com/explore/tags/${h}/`);

// Step 1: hashtag posts
console.log('Discovery: arrancando hashtag scraper en', HASHTAGS.join(', '));
const posts = await apifyRunAndWait('apify~instagram-scraper', {
  directUrls,
  resultsType: 'posts',
  resultsLimit: 100,
});

// Step 2: usernames únicos de las últimas 72h
const cutoff = Date.now() - 72 * 3600 * 1000;
const recentPosts = posts.filter(p => p.timestamp && new Date(p.timestamp).getTime() > cutoff);
const usernameSet = new Set(recentPosts.map(p => p.ownerUsername).filter(Boolean));
const usernames = [...usernameSet].slice(0, 50);
console.log(`Posts recientes: ${recentPosts.length} — Usernames únicos: ${usernames.length}`);

if (!usernames.length) return [{ json: { discovered: 0, note: 'sin usernames' } }];

// Step 3: profile scraping
console.log('Scrapeando perfiles...');
const profiles = await apifyRunAndWait('apify~instagram-profile-scraper', { usernames }, 300000);
console.log(`Perfiles recibidos: ${profiles.length}`);

// Step 4: guardar raw_prospects
const rows = profiles
  .filter(p => p.username)
  .map(p => ({
    source: 'instagram',
    source_id: p.username,
    handle: p.username,
    url: `https://www.instagram.com/${p.username}/`,
    raw_data: p,
  }));

await supabaseUpsert('raw_prospects', rows);
console.log(`raw_prospects upserted: ${rows.length}`);

return [{ json: { discovered: rows.length, sample_usernames: usernames.slice(0, 5) } }];

// Stage 2: Enriquecimiento y filtro duro
// Filtros: followers 5K-100K, externalUrl presente, biography en español
// Lee raw_prospects de las últimas 2h y guarda en qualified_prospects.

const SUPABASE_URL = process.env.SUPABASE_URL;
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_KEY;

const SB_HEADERS = {
  'Content-Type': 'application/json',
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'apikey': SUPABASE_KEY,
};

async function sbGet(path) {
  const r = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, { headers: SB_HEADERS });
  if (!r.ok) throw new Error(`sbGet ${path}: ${await r.text()}`);
  return r.json();
}

async function sbInsert(table, rows) {
  if (!rows.length) return [];
  const r = await fetch(`${SUPABASE_URL}/rest/v1/${table}`, {
    method: 'POST',
    headers: { ...SB_HEADERS, 'Prefer': 'return=representation,resolution=ignore-duplicates' },
    body: JSON.stringify(rows),
  });
  if (!r.ok) throw new Error(`sbInsert ${table}: ${await r.text()}`);
  return r.json();
}

// Palabras que delatan que la bio NO es en español (otros idiomas comunes)
const NON_ES_HINTS = ['i am', 'i help', 'follow me', 'dm me', 'link in bio',
  'curso de', 'sou ', 'meu ', 'nosso ', 'aprenda ', 'você ', 'negócios',  // pt-BR
];

function looksSpanish(bio) {
  if (!bio) return false;
  const b = bio.toLowerCase();
  // Si tiene indicadores de otro idioma, rechazar
  if (NON_ES_HINTS.some(h => b.includes(h))) return false;
  // Si tiene palabras españolas comunes del nicho, aceptar
  const esWords = ['negocio', 'empresa', 'curso', 'formación', 'automatiz', 'inteligencia',
    'mentor', 'emprendedor', 'estrategia', 'marca', 'cliente', 'aprende', 'revenue'];
  return esWords.some(w => b.includes(w));
}

// Obtener nicho ia-negocios
const [niche] = await sbGet(`niches?slug=eq.ia-negocios&select=id`);
if (!niche) throw new Error('Nicho ia-negocios no encontrado en BD');
const nicheId = niche.id;

// Leer raw_prospects de las últimas 3h sin qualified correspondiente
const cutoff = new Date(Date.now() - 3 * 3600 * 1000).toISOString();
const rawProspects = await sbGet(
  `raw_prospects?source=eq.instagram&discovered_at=gte.${cutoff}&select=id,handle,raw_data`
);
console.log(`raw_prospects a evaluar: ${rawProspects.length}`);

const qualified = [];

for (const rp of rawProspects) {
  const p = rp.raw_data;
  const followers = p.followersCount || 0;
  const hasLanding = !!p.externalUrl;
  const spanishBio = looksSpanish(p.biography);

  // Filtros duros: followers, landing, idioma
  if (followers < 5000 || followers > 100000) continue;
  if (!hasLanding) continue;
  if (!spanishBio) continue;

  qualified.push({
    raw_prospect_id: rp.id,
    handle: rp.handle,
    platform_links: {
      instagram: `https://www.instagram.com/${rp.handle}/`,
      landing: p.externalUrl,
    },
    followers,
    ads_count: 0,      // Se completará en sprint 2 con Meta Ads
    language: 'es',
    detected_niche_id: nicheId,
    detected_mode: 'both',
  });
}

console.log(`Calificados: ${qualified.length} de ${rawProspects.length}`);
await sbInsert('qualified_prospects', qualified);

return [{ json: { qualified: qualified.length, evaluated: rawProspects.length } }];

// Stage 3: Análisis profundo con Claude (§8.1 funnel + §8.3 value_opportunities)
// Solo procesa prospectos sin análisis o con análisis >7 días.
// Guarda en prospect_analyses.

const SUPABASE_URL = process.env.SUPABASE_URL;
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_KEY;
const ANTHROPIC_KEY = process.env.ANTHROPIC_API_KEY;

const SB_HEADERS = {
  'Content-Type': 'application/json',
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'apikey': SUPABASE_KEY,
};

async function sbGet(path) {
  const r = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, { headers: SB_HEADERS });
  if (!r.ok) throw new Error(`sbGet: ${await r.text()}`);
  return r.json();
}

async function sbUpsert(table, rows, conflict) {
  if (!rows.length) return [];
  const r = await fetch(`${SUPABASE_URL}/rest/v1/${table}?on_conflict=${conflict}`, {
    method: 'POST',
    headers: { ...SB_HEADERS, 'Prefer': 'return=representation,resolution=merge-duplicates' },
    body: JSON.stringify(rows),
  });
  if (!r.ok) throw new Error(`sbUpsert ${table}: ${await r.text()}`);
  return r.json();
}

async function claude(prompt, maxTokens = 1024) {
  const r = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': ANTHROPIC_KEY,
      'anthropic-version': '2023-06-01',
    },
    body: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: maxTokens,
      messages: [{ role: 'user', content: prompt }],
    }),
  });
  if (!r.ok) throw new Error(`Claude: ${await r.text()}`);
  const data = await r.json();
  const raw = data.content[0].text.trim();
  const match = raw.match(/\{[\s\S]*\}|\[[\s\S]*\]/);
  try { return JSON.parse(match ? match[0] : raw); }
  catch { return { raw }; }
}

async function fetchLandingText(url) {
  try {
    const controller = new AbortController();
    setTimeout(() => controller.abort(), 8000);
    const r = await fetch(url, {
      signal: controller.signal,
      headers: { 'User-Agent': 'Mozilla/5.0 (compatible; bot)' },
    });
    const html = await r.text();
    // Extraer texto legible (quitar tags HTML)
    return html.replace(/<script[\s\S]*?<\/script>/gi, '')
               .replace(/<style[\s\S]*?<\/style>/gi, '')
               .replace(/<[^>]+>/g, ' ')
               .replace(/\s+/g, ' ')
               .trim()
               .slice(0, 6000);
  } catch {
    return null;
  }
}

// Prospectos calificados sin análisis o con análisis >7 días
const cutoff7d = new Date(Date.now() - 7 * 86400000).toISOString();
const prospects = await sbGet(
  `qualified_prospects?select=id,handle,platform_links,followers&order=qualified_at.desc&limit=20`
);
const existingAnalyses = await sbGet(
  `prospect_analyses?analyzed_at=gte.${cutoff7d}&select=prospect_id`
);
const analyzedIds = new Set(existingAnalyses.map(a => a.prospect_id));

const toAnalyze = prospects.filter(p => !analyzedIds.has(p.id));
console.log(`Prospectos a analizar: ${toAnalyze.length}`);

const analyses = [];

for (const p of toAnalyze) {
  const landingUrl = p.platform_links?.landing;
  let landingText = '';
  if (landingUrl) {
    landingText = await fetchLandingText(landingUrl) || '';
    console.log(`  @${p.handle}: landing ${landingText ? 'OK' : 'no accesible'} (${landingUrl.slice(0, 60)})`);
  }

  // Prompt §8.1 — análisis del embudo
  const funnelPrompt = `Eres un experto en embudos de venta de infoproductos en español.

Te paso el texto de la landing de un infoproductor. Analiza:
1. PROMESA principal (1 frase)
2. ESTRUCTURA: qué secciones tiene y en qué orden
3. PRUEBA SOCIAL: ¿hay? ¿dónde? ¿qué tipo?
4. CTA: ¿qué pide?
5. FRICCIONES: máximo 3 cosas que podrían bajar conversión
6. FORTALEZAS: máximo 2 cosas que están haciendo bien

Devuelve JSON con esos 6 campos.

Handle: @${p.handle}
Followers: ${p.followers}
LANDING:
${landingText || '[No accesible — analiza solo con los datos del perfil de IG]'}`;

  const funnelAnalysis = await claude(funnelPrompt, 800);

  // Prompt §8.3 — value_opportunities
  const valuePrompt = `Eres consultor de marketing para infoproductos en español. Tu trabajo es identificar
oportunidades concretas donde alguien podría aportar valor a este infoproductor en un primer contacto.

Tienes:
- Análisis del embudo: ${JSON.stringify(funnelAnalysis)}
- Handle: @${p.handle}
- Followers: ${p.followers}

Identifica 2-4 OPORTUNIDADES DE VALOR. Cada una debe:
- Ser específica (no genérica tipo "mejorar copy")
- Basarse en algo concreto observado
- Ser accionable en horas/días
- NO ser un pitch de "contrátame": es un insight gratis

Devuelve JSON array con objetos: { "area": "Embudo"|"Anuncios"|"Reels"|"Posicionamiento"|"Oferta", "observation": "...", "suggested_value": "..." }`;

  const valueOpportunities = await claude(valuePrompt, 800);

  // Clasificación sencilla launch vs evergreen basada en texto del landing
  const hasLaunchSignals = /masterclass|directo|webinar|reto|día \d|plaza|esta semana/i.test(landingText);

  analyses.push({
    prospect_id: p.id,
    funnel_summary: JSON.stringify(funnelAnalysis),
    vsl_transcript: null,
    creatives_analysis: null,
    reels_summary: null,
    value_opportunities: Array.isArray(valueOpportunities) ? valueOpportunities : [valueOpportunities],
    launch_date: null,
    classification: hasLaunchSignals ? 'launch' : 'evergreen',
    score: Math.min(100, Math.round((p.followers / 1000) * 2 + (landingText ? 20 : 0))),
    analyzed_at: new Date().toISOString(),
  });

  console.log(`  @${p.handle}: análisis OK — score ${analyses[analyses.length - 1].score}`);
}

await sbUpsert('prospect_analyses', analyses, 'prospect_id');
console.log(`prospect_analyses guardados: ${analyses.length}`);

return [{ json: { analyzed: analyses.length } }];

// Stage 4: Matching + generación de mensajes con Claude (§8.4)
// Selecciona top 5 prospectos para el founder, genera un mensaje por cada uno.

const SUPABASE_URL = process.env.SUPABASE_URL;
const SUPABASE_KEY = process.env.SUPABASE_SERVICE_KEY;
const ANTHROPIC_KEY = process.env.ANTHROPIC_API_KEY;
const CLOSER_EMAIL = 'opombo84@gmail.com';

const SB_HEADERS = {
  'Content-Type': 'application/json',
  'Authorization': `Bearer ${SUPABASE_KEY}`,
  'apikey': SUPABASE_KEY,
};

async function sbGet(path) {
  const r = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, { headers: SB_HEADERS });
  if (!r.ok) throw new Error(`sbGet: ${await r.text()}`);
  return r.json();
}

async function sbInsert(table, rows) {
  if (!rows.length) return [];
  const r = await fetch(`${SUPABASE_URL}/rest/v1/${table}`, {
    method: 'POST',
    headers: { ...SB_HEADERS, 'Prefer': 'return=representation' },
    body: JSON.stringify(rows),
  });
  if (!r.ok) throw new Error(`sbInsert ${table}: ${await r.text()}`);
  return r.json();
}

async function sbPatch(table, id, data) {
  const r = await fetch(`${SUPABASE_URL}/rest/v1/${table}?id=eq.${id}`, {
    method: 'PATCH',
    headers: { ...SB_HEADERS, 'Prefer': 'return=minimal' },
    body: JSON.stringify(data),
  });
  if (!r.ok) throw new Error(`sbPatch ${table}: ${await r.text()}`);
}

async function claude(system, user, maxTokens = 400) {
  const r = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': ANTHROPIC_KEY,
      'anthropic-version': '2023-06-01',
    },
    body: JSON.stringify({
      model: 'claude-sonnet-4-6',
      max_tokens: maxTokens,
      system,
      messages: [{ role: 'user', content: user }],
    }),
  });
  if (!r.ok) throw new Error(`Claude: ${await r.text()}`);
  const data = await r.json();
  return data.content[0].text.trim();
}

// ── Obtener closer (founder) ──────────────────────────────────────────────────
const [closer] = await sbGet(`closers?email=eq.${CLOSER_EMAIL}&select=id,tone_profile,selected_niches`);
if (!closer) throw new Error('Closer no encontrado: ' + CLOSER_EMAIL);

const tp = closer.tone_profile;
const ss = tp?.style_summary || {};
const transcripts = tp?.transcripts || [];

// ── Candidatos: prospectos con análisis, sin asignación hoy ──────────────────
const todayStart = new Date();
todayStart.setHours(0, 0, 0, 0);

const analyses = await sbGet(
  `prospect_analyses?select=id,prospect_id,value_opportunities,classification,score,funnel_summary`
  + `&score=gte.0&order=score.desc&limit=30`
);

// Prospectos ya asignados hoy a este closer
const todayAssignments = await sbGet(
  `lead_assignments?closer_id=eq.${closer.id}&assigned_at=gte.${todayStart.toISOString()}&select=prospect_id`
);
const alreadyAssigned = new Set(todayAssignments.map(a => a.prospect_id));

const candidates = analyses.filter(a => !alreadyAssigned.has(a.prospect_id));
const top = candidates.slice(0, 5);
console.log(`Candidatos: ${candidates.length} — Seleccionados: ${top.length}`);

if (!top.length) return [{ json: { messages: 0, note: 'sin candidatos nuevos' } }];

// ── System prompt de tono del closer ─────────────────────────────────────────
const systemPrompt = `Eres este closer escribiendo un mensaje de Instagram a un infoproductor.

PERFIL DEL CLOSER (cómo habla):
Variante de español: ${ss.spanish_variant || 'Español peninsular'}
Registro: ${ss.register || 'Cercano, conversacional'}
Energía: ${ss.energy || 'medio-alto'}
Frases características: ${(ss.characteristic_phrases || []).join(', ')}
Muletillas: ${(ss.filler_words || []).join(', ')}
Aperturas típicas: ${(ss.typical_openers || []).join(', ')}
Formalidad: ${ss.formality_level || 2}/5

EJEMPLOS DE CÓMO HABLA ESTE CLOSER:
${transcripts.slice(0, 3).map(t => t.text?.slice(0, 400)).join('\n---\n')}`;

// ── Generar mensajes ──────────────────────────────────────────────────────────
const messages = [];
const now = new Date();
const expires = new Date(now.getTime() + 24 * 3600 * 1000);

for (const analysis of top) {
  // Obtener datos del prospecto
  const [qp] = await sbGet(`qualified_prospects?id=eq.${analysis.prospect_id}&select=handle,platform_links,followers`);
  if (!qp) continue;

  const opportunities = Array.isArray(analysis.value_opportunities)
    ? analysis.value_opportunities
    : [];
  if (!opportunities.length) continue;

  // Elegir la mejor oportunidad (la más específica — la primera por ahora)
  const vo = opportunities[0];

  const userPrompt = `INFOPRODUCTOR DESTINATARIO:
Handle: @${qp.handle}
Nicho: IA aplicada a negocios
Seguidores: ${qp.followers}

PUNTO DE VALOR A APORTAR:
Área: ${vo.area}
Observación: ${vo.observation}
Valor sugerido: ${vo.suggested_value}

INSTRUCCIONES CRÍTICAS:
1. Escribe como esta persona HABLA, no como una persona escribe. Mantén su ritmo y muletillas si caben.
2. El mensaje aporta valor genuino sobre el punto identificado. NO es un pitch de venta.
3. NO menciones que eres closer. NO ofrezcas servicios. NO pidas llamada.
4. Tono: como si fueras un colega del nicho que ha visto algo interesante y quiere compartirlo.
5. Longitud: 60-120 palabras.
6. Empieza llamándole por su @handle.
7. Cierra con una pregunta abierta o una observación que invite a respuesta natural, no con CTA.

Devuelve solo el texto del mensaje, sin comillas ni explicaciones.`;

  const messageText = await claude(systemPrompt, userPrompt, 300);
  console.log(`  @${qp.handle}: mensaje generado (${messageText.split(' ').length} palabras)`);

  // Crear lead_assignment
  const [assignment] = await sbInsert('lead_assignments', [{
    prospect_id: analysis.prospect_id,
    closer_id: closer.id,
    assigned_at: now.toISOString(),
    expires_at: expires.toISOString(),
    status: 'pending',
  }]);

  // Guardar mensaje generado
  if (assignment?.id) {
    await sbInsert('generated_messages', [{
      assignment_id: assignment.id,
      message_text: messageText,
      value_point: vo.observation,
    }]);
    messages.push({ handle: qp.handle, message: messageText.slice(0, 80) + '...' });
  }
}

console.log(`Mensajes generados: ${messages.length}`);
return [{ json: { messages: messages.length, preview: messages } }];
